public class PrimitiveDemo {
    public static void main(String[] args) {
        byte   b  = 100;
        short  s  = 30000;
        int    i  = 2_000_000;    // Underscore separators (Java 7+) for readability
        long   l  = 9_000_000_000L;  // 'L' suffix is REQUIRED for long literals > int range
        float  f  = 3.14f;        // 'f' suffix is REQUIRED for float literals
        double d  = 3.141592653589793;
        char   c  = 'A';          // Single quotes
        boolean flag = true;

        // Print sizes using wrapper class constants
        System.out.println(Integer.MAX_VALUE);   // 2147483647
        System.out.println(Integer.MIN_VALUE);   // -2147483648
        System.out.println(Long.MAX_VALUE);      // 9223372036854775807
        System.out.println(Double.MAX_VALUE);    // 1.7976931348623157E308

        // char behaves as a number
        char x = 'A';
        System.out.println(x);       // A
        System.out.println(x + 0);   // 65  (int arithmetic)
        System.out.println((char)(x + 1)); // B
    }
}

public class WideningDemo {
    public static void main(String[] args) {
        byte   b = 42;
        short  s = b;     // byte → short  (automatic)
        int    i = s;     // short → int   (automatic)
        long   l = i;     // int → long    (automatic)
        float  f = l;     // long → float  (automatic) — may lose precision!
        double d = f;     // float → double (automatic)

        System.out.println(b); // 42
        System.out.println(d); // 42.0  (went through the whole chain)

        // char widens to int
        char c = 'Z';          // Unicode value 90
        int code = c;          // char → int (automatic)
        System.out.println(code); // 90

        // Widening in expressions: smaller types promote to int
        byte x = 10, y = 20;
        // byte result = x + y; // COMPILE ERROR! x+y promotes to int
        int result = x + y;    // OK
        System.out.println(result); // 30
    }
}

public class NarrowingDemo {
    public static void main(String[] args) {
        // double → int: truncates (removes decimal part)
        double d = 9.99;
        int i = (int) d;
        System.out.println(i);   // 9  (NOT rounded, just truncated)

        // large int → byte: wraps around (overflow)
        int big = 200;
        byte b = (byte) big;
        System.out.println(b);   // -56  (200 - 256 = -56, two's complement)

        // large int → byte: another example
        int val = 130;
        byte b2 = (byte) val;
        System.out.println(b2);  // -126  (130 - 256 = -126)

        // double → long: truncates then stores
        double pi = 3.99999;
        long l = (long) pi;
        System.out.println(l);   // 3  (decimal part gone)

        // int → char
        int ascii = 65;
        char c = (char) ascii;
        System.out.println(c);   // A

        // Narrowing formula for byte overflow:
        // if value > 127: result = value - 256
        // if value < -128: result = value + 256
        System.out.println((byte) 128);  // -128
        System.out.println((byte) 256);  // 0    (256 - 256 = 0)
        System.out.println((byte) 257);  // 1    (257 - 256 = 1)
    }
}

import java.util.ArrayList;
public class AutoboxingDemo {
    public static void main(String[] args) {
        // AUTOBOXING: primitive → wrapper (automatic)
        int primitive = 42;
        Integer wrapper = primitive;      // int auto-boxed to Integer
        Integer explicit = Integer.valueOf(42); // same thing, explicit

        // UNBOXING: wrapper → primitive (automatic)
        int backToPrimitive = wrapper;    // Integer unboxed to int

        // Collections REQUIRE wrappers
        ArrayList<Integer> list = new ArrayList<>();
        list.add(10);   // autoboxing: 10 → Integer(10)
        list.add(20);
        int first = list.get(0);  // unboxing: Integer(10) → 10
        System.out.println(first); // 10

        // DANGER: == vs .equals() with wrappers
        Integer a = 100;  // cached  (-128 to 127 are cached by JVM)
        Integer b = 100;
        System.out.println(a == b);       // true  (same cached object)

        Integer c = 200;  // NOT cached — new objects
        Integer d = 200;
        System.out.println(c == d);       // false! (different objects)
        System.out.println(c.equals(d));  // true  (always use .equals())

        // Null unboxing causes NullPointerException!
        Integer n = null;
        // int x = n;  // RUNTIME ERROR: NullPointerException
    }
}

public class PromotionDemo {
    public static void main(String[] args) {
        int    i = 10;
        long   l = 20L;
        float  f = 3.0f;
        double d = 4.0;

        // int + long → long
        long r1 = i + l;
        System.out.println(r1);   // 30

        // long + float → float
        float r2 = l + f;
        System.out.println(r2);   // 23.0

        // float + double → double
        double r3 = f + d;
        System.out.println(r3);   // 7.0

        // int / int → int (even stored in double!)
        double avg = 7 / 2;
        System.out.println(avg);  // 3.0  (integer 3, then widened)

        // Fix: make one operand double
        double avg2 = 7.0 / 2;
        System.out.println(avg2); // 3.5

        // char + int → int
        char c = 'A';   // value 65
        System.out.println(c + 1);   // 66 (int)
        System.out.println((char)(c + 1)); // B
    }
}

