public class Q2 {
    public static void main(String[] args) {
        byte a = 100;
        byte b = 100;
        // byte c = a + b;  // This would be compile error
        int  c = a + b;
        System.out.println(c);

        byte d = (byte)(a + b);
        System.out.println(d);

        byte e = 50;
        e += 100;   // compound assignment has implicit cast!
        System.out.println(e);
    }
}

public class Q3 {
