        Integer p = 128;
        Integer q = 128;
        System.out.println(p == q);
        System.out.println(p.equals(q));
    }
}

public class Q4 {
    public static void main(String[] args) {
        int   i = 5;
        long  l = 10L;
        float f = 2.5f;

        System.out.println(i + l);    // A
        System.out.println(l + f);    // B
        System.out.println(i / 2);    // C
        System.out.println(i / 2.0);  // D

        long result = i * 1000000000;  // E — careful!
        System.out.println(result);
    }
}

public class TypeErrors {
    public static void main(String[] args) {
        long bigNum = 10000000000;       // Line 3
        float precise = 3.14159265358;   // Line 4
        byte small = 200;                // Line 5
        char letter = -1;                // Line 6
        int count = 0;
        count = count + 1.0;             // Line 9
        System.out.println(count);
    }
}

