public class TypeErrors {
    public static void main(String[] args) {
        long bigNum = 10000000000L;       // L suffix
        float precise = 3.14159265358f;   // f suffix
        byte small = (byte) 200;          // explicit narrow cast
        char letter = (char) -1;          // explicit cast ('\uFFFF')
        int count = 0;
        count = count + 1;                // use int literal, not 1.0
        System.out.println(count);
    }
}

